import React, { useEffect, useState } from "react"
import Fade from "./animations/Fade"
import { useLanguage } from "../contexts/LanguageContext"
import data, { getText } from "../data"



const Header = () => {
  const { language } = useLanguage();
  // Track orientation for responsive adjustments, initialize with a default value
  const [isLandscape, setIsLandscape] = useState(false);
  const [isIOS, setIsIOS] = useState(false);
  const [isDesktop, setIsDesktop] = useState(false);

  useEffect(() => {
    // This code only runs in the browser after component mounts
    // Check if window is defined (browser environment)
    if (typeof window !== 'undefined') {
      // Detect iOS
      const iOS = /iPad|iPhone|iPod/.test(navigator.userAgent) ||
        (navigator.platform === 'MacIntel' && navigator.maxTouchPoints > 1);
      setIsIOS(iOS);

      // Detect if desktop
      const userAgent = navigator.userAgent.toLowerCase();
      const isMobile = /android|webos|iphone|ipad|ipod|blackberry|iemobile|opera mini|mobile/i.test(userAgent);
      setIsDesktop(!isMobile);

      // Set initial value
      setIsLandscape(window.innerWidth > window.innerHeight);

      const handleResize = () => {
        setIsLandscape(window.innerWidth > window.innerHeight);
        setIsDesktop(window.innerWidth >= 1024); // Consider devices with width >= 1024px as desktop
      };

      try {
        window.addEventListener("resize", handleResize);
      } catch (error) {
        console.warn('Error adding resize listener:', error);
      }
      // Initial check
      handleResize();

      return () => {
        try {
          window.removeEventListener("resize", handleResize);
        } catch (error) {
          console.warn('Error removing resize listener:', error);
        }
      };
    }
  }, []);

  // For mobile devices (iOS or Android), use the more stable structure that prevents layout jumping
  if (isIOS || !isDesktop) {
    return (
      <div className="section" id="home">
        <div className="container">
          <div className="header-wrapper ios-device">
            {/* Background image for mobile devices */}
            <div
              className="ios-background"
              style={{
                backgroundColor: '#ffffff'
              }}
            />

            <div className="content-wrapper">
              <Fade bottom>
                <h2 style={{ color: "var(--text-dark-primary)" }}>
                  {getText({ en: "Hi, " }, language)}
                  <span className="mobile-wrap">
                    {getText({ en: "I am " }, language)}<span className="name-gradient">{getText(data.name, language)}</span>.
                  </span>
                </h2>
              </Fade>

              <Fade bottom>
                <p style={{ color: "var(--text-dark-primary)" }}>{getText(data.headerParagraph, language)}</p>
              </Fade>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // For desktop devices, use the original parallax implementation
  return (
    <div className="section" id="home">
      <div className="container">
        <div
          className={`header-wrapper ${isLandscape ? 'landscape' : 'portrait'} desktop`}
          style={{
            backgroundColor: '#ffffff'
          }}
        >
          <Fade bottom>
            <h2 style={{ color: "var(--text-dark-primary)" }}>
              {getText({ en: "Hi, " }, language)}
              <span className="mobile-wrap">
                {getText({ en: "I am " }, language)}<span className="name-gradient">{getText(data.name, language)}</span>.
              </span>
            </h2>
          </Fade>

          <Fade bottom>
            <p style={{ color: "var(--text-dark-primary)" }}>{getText(data.headerParagraph, language)}</p>
          </Fade>
        </div>
      </div>
    </div>
  );
}

export default Header
